#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, D;
        scanf("%d %d %d", &N, &K, &D);
        long long dp[N + 1][K + 1] = {0};
        dp[0][0] = 1;
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= K; j++) {
                for (int k = 1; k <= D; k++) {
                    if (i - k >= 0 && j - 1 >= 0) {
                        dp[i][j] = (dp[i][j] + dp[i - k][j - 1]) % MOD;
                    }
                }
            }
        }
        printf("%lld\n", dp[N][K]);
    }
    return 0;
}

